fn solve(n: i64, edges: Vec<Vec<i64>>, label: String) -> i64 {
    let n = n as usize;
    let label_chars: Vec<char> = label.chars().collect();
    let mut adj = vec![vec![]; n];
    for edge in edges {
        let u = edge[0] as usize;
        let v = edge[1] as usize;
        adj[u].push(v);
        adj[v].push(u);
    }

    let mut max_len = 0;
    for start in 0..n {
        let mut visited = vec![false; n];
        let mut path = Vec::new();
        dfs(&adj, &label_chars, start, &mut visited, &mut path, &mut max_len);
    }
    max_len as i64
}

fn dfs(
    adj: &Vec<Vec<usize>>,
    label_chars: &Vec<char>,
    node: usize,
    visited: &mut Vec<bool>,
    path: &mut Vec<char>,
    max_len: &mut usize,
) {
    visited[node] = true;
    path.push(label_chars[node]);

    if is_palindrome(path) {
        *max_len = (*max_len).max(path.len());
    }

    for &neighbor in &adj[node] {
        if !visited[neighbor] {
            dfs(adj, label_chars, neighbor, visited, path, max_len);
        }
    }

    path.pop();
    visited[node] = false;
}

fn is_palindrome(s: &[char]) -> bool {
    let len = s.len();
    for i in 0..len / 2 {
        if s[i] != s[len - 1 - i] {
            return false;
        }
    }
    true
}
